156	// PreMergeChecksReason is the canonical Reason prefix written onto preserved
157	// landings whose preservation was triggered by the pre-merge checks gate.
158	// Callers (status classifiers, dashboards) match on this prefix to bucket
159	// pre-merge-checks misses apart from generic merge conflicts or gate failures.
160	const PreMergeChecksReason = "pre-merge checks blocked"
