300	// preMergeChangedPaths returns the list of paths changed between baseRev and
301	// resultRev as reported by `git diff --name-only`. Returns (nil, nil) when
302	// either rev is empty (e.g. a no-changes attempt that should not exercise the
303	// path-glob filters at all).
304	func preMergeChangedPaths(projectRoot, baseRev, resultRev string) ([]string, error) {
305		if baseRev == "" || resultRev == "" || baseRev == resultRev {
306			return nil, nil
307		}
308		out, err := internalgit.Command(context.Background(), projectRoot, "diff", "--name-only", baseRev, resultRev).CombinedOutput()
309		if err != nil {
310			return nil, fmt.Errorf("git diff --name-only %s %s: %s: %w", baseRev, resultRev, strings.TrimSpace(string(out)), err)
311		}
312		var paths []string
313		for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
314			if p := strings.TrimSpace(line); p != "" {
315				paths = append(paths, p)
316			}
317		}
318		return paths, nil
319	}
