233	func recordPostAttemptTriageEvent(store BeadEventAppender, beadID string, report ExecuteBeadReport, triage TriageResult, actor string, createdAt time.Time) {
234		if store == nil || beadID == "" {
235			return
236		}
237		triage = normalizeTriageResult(triage)
238		hasClassification := triage.Classification != ""
239		hasWarnings := len(triage.DecodeWarnings) > 0 || triage.Malformed
240		if !hasClassification && !hasWarnings {
241			return
242		}
243		amendments := triage.SuggestedAmendments
244		if amendments == nil {
245			amendments = []TriageAmendment{}
246		}
247		followups := triage.SuggestedFollowupBeads
248		if followups == nil {
249			followups = []FollowupBead{}
250		}
251		body := map[string]any{
252			"classification":           triage.Classification,
253			"recommended_action":       triage.RecommendedAction,
254			"rationale":                triage.Rationale,
255			"suggested_amendments":     amendments,
256			"suggested_followup_beads": followups,
257			"status":                   report.Status,
258			"detail":                   report.Detail,
259			"base_rev":                 report.BaseRev,
260			"result_rev":               report.ResultRev,
261			"session_id":               report.SessionID,
262		}
263		if len(triage.DecodeWarnings) > 0 {
264			body["decode_warnings"] = triage.DecodeWarnings
265		}
266		if triage.Malformed {
267			body["malformed"] = true
268		}
269		encoded, err := json.Marshal(body)
270		if err != nil {
271			return
272		}
273		kind := "bead-quality.triage"
274		summary := triage.Classification
275		if !isRecognizedTriageClassification(triage.Classification) {
276			kind = "bead-quality.triage-warning"
277			summary = "malformed triage output"
278			if triage.Classification != "" {
279				summary = "unusable triage classification: " + triage.Classification
280			} else if len(triage.DecodeWarnings) > 0 && triage.DecodeWarnings[0].Warning != "" {
281				summary = triage.DecodeWarnings[0].Warning
282			}
283		} else if triage.RecommendedAction != "" {
284			summary = triage.Classification + ": " + triage.RecommendedAction
285			if len(triage.DecodeWarnings) > 0 {
286				summary += fmt.Sprintf(" (warnings=%d)", len(triage.DecodeWarnings))
287			}
288		}
289		_ = store.AppendEvent(beadID, bead.BeadEvent{
290			Kind:      kind,
291			Summary:   summary,
292			Body:      string(encoded),
293			Actor:     actor,
294			Source:    "ddx agent execute-loop",
295			CreatedAt: createdAt.UTC(),
296		})
297	}
